def match(pattern, data, env):
    """Try to extend env so that pattern matches data. Return env or None."""
    if isinstance(pattern, str) and pattern.startswith("?"):
        # A variable matches anything; record what it must equal.
        if pattern in env and env[pattern] != data:
            return None              # already bound to something else
        env = dict(env)
        env[pattern] = data
        return env
    if isinstance(pattern, list) and isinstance(data, list):
        # Handle a trailing "dot" variable: ["a", ".", "?rest"]
        if len(pattern) == 3 and pattern[1] == ".":
            env = match(pattern[0], data[0], env) if data else None
            if env is None:
                return None
            return match(pattern[2], data[1:], env)
        if len(pattern) != len(data):
            return None
        for p, d in zip(pattern, data):
            env = match(p, d, env)
            if env is None:
                return None
        return env
    # Two plain symbols (or anything else) must be identical.
    return env if pattern == data else None


# Match (dog (name clinton) (color ?color)) against clinton's record.
pattern = ["dog", ["name", "clinton"], ["color", "?color"]]
record  = ["dog", ["name", "clinton"], ["color", "white"]]
print(match(pattern, record, {}))          # {'?color': 'white'}

# Bind a whole sub-list: (dog (name clinton) ?info)
print(match(["dog", ["name", "clinton"], "?info"], record, {}))   # {'?info': ['color', 'white']}

# A trailing dot variable captures the rest of a list.
print(match(["?first", ".", "?rest"], ["a", "b", "c"], {}))       # {'?first': 'a', '?rest': ['b', 'c']}
